const Projects = () => {
    const items = [
        {number: "001", title: "Blog Website"},
        {number: "002", title: "Project 2"},
        {number: "003", title: "Project 3"},
        {number: "004", title: "Project 4"},
        {number: "005", title: "Project 5"}
    ]

  return (
    <div className="project-list">
        {items.map((item, index) => (
            <Link className="project-item" key={index}>
                <Link className="project-number">{item.number}</Link>
                <Link className="project-title">{item.title}</Link>
                <Link className="project-line"></Link>
            </Link>
        ))}
    </div>
  );
};

export default Projects;
